import json
import pymysql
from aws_lambda_powertools import Tracer, Logger

tracer = Tracer()
logger = Logger()

def lambda_handler(event, context):
    # Get search parameters from API Gateway event
    params = json.loads(event["body"])

    # Build SQL query dynamically based on search parameters
    query = "SELECT * FROM products WHERE 1=1"
    for key in params:
        if key == "name":
            query += f" AND name LIKE '%{params[key]}%'"
        elif key == "category":
            query += f" AND category = '{params[key]}'"
        elif key == "price":
            query += f" AND price >= {params[key]}"

    # Connect to RDS MySQL database using pymysql
    conn = pymysql.connect(host="your_rds_instance_endpoint", user="your_username", password="your_password", db="your_database")
    cursor = conn.cursor()

    # Execute SQL query and retrieve results
    cursor.execute(query)
    results = cursor.fetchall()

    # Close database connection
    cursor.close()
    conn.close()

    # Return search results as JSON response
    return {
        "statusCode": 200,
        "body": json.dumps(results)
    }